@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@{
    var context = new CarouselContext(
        _contentId,
        Orientation,
        _canScrollPrev && !Disabled,
        _canScrollNext && !Disabled,
        EventCallback.Factory.Create(this, ScrollPrev),
        EventCallback.Factory.Create(this, ScrollNext),
        RegisterItem,
        UnregisterItem
    );
}

@* preventDefault is key-selective via JS (see OnAfterRenderAsync): the blanket
   @onkeydown:preventDefault="true" cancelled EVERY key bubbling through the
   region — Tab couldn't leave (keyboard trap) and typing/Space inside
   interactive slide content was dead. *@
<div id="@EffectiveRootId" role="region" aria-roledescription="carousel" class="@CssClass"
     @onkeydown="HandleKeyDown"
     @onpointerenter="OnPointerEnter" @onpointerleave="OnPointerLeave"
     @onfocusin="OnFocusIn" @onfocusout="OnFocusOut"
     @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
    @if (ShowIndicators && _items.Count > 1)
    {
        @* Indicator dots — one per slide, current is highlighted. Each jumps
           straight to its slide. Rendered in a tablist-ish row; buttons carry
           an aria-label so they're operable by name. *@
        <div class="@IndicatorWrapClass" role="group" aria-label="@L["Carousel.Indicators"]">
            @for (var i = 0; i < _items.Count; i++)
            {
                var index = i;
                var isActive = index == _currentIndex;
                <button type="button"
                        class="@IndicatorDotClass(isActive)"
                        aria-label="@L["Carousel.GoToSlide", index + 1]"
                        aria-current="@(isActive ? "true" : null)"
                        @onclick="() => ScrollTo(index)"></button>
            }
        </div>
    }
    @* Visually-hidden live region announces slide changes to assistive
       tech. Auto-play decks or programmatic ScrollTo would otherwise be
       silent. Polite (not assertive) so it doesn't interrupt other speech. *@
    <span aria-live="polite" aria-atomic="true" class="sr-only">@SlideAnnouncement</span>
</div>

@inject IComponentInteropService Interop
@inject ThemeService Theme
@inject Microsoft.Extensions.Options.IOptions<Lumeo.Services.LumeoGestureOptions> GestureOpts

@code {
    // A scoped <DirectionProvider> cascades its direction here; when present it
    // wins over the global ThemeService so a subtree can be RTL even if the app
    // is LTR (and vice versa). Null when no provider wraps this carousel — then
    // the ambient theme direction applies.
    [CascadingParameter(Name = "LumeoDirection")] private LayoutDirection? ScopedDirection { get; set; }
    private LayoutDirection EffectiveDirection => ScopedDirection ?? Theme.CurrentDirection;

    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Horizontal;
    [Parameter] public bool Loop { get; set; }
    [Parameter] public bool Disabled { get; set; }

    /// <summary>Advance slides automatically on a timer. Pairs well with
    /// <see cref="Loop"/> so the deck wraps instead of stopping at the end.</summary>
    [Parameter] public bool Autoplay { get; set; }

    /// <summary>Autoplay tick interval in milliseconds. Defaults to 4000.</summary>
    [Parameter] public int AutoplayInterval { get; set; } = 4000;

    /// <summary>Pause autoplay while the pointer is over the carousel or focus
    /// is inside it (so users can read / interact). Defaults to true.</summary>
    [Parameter] public bool PauseOnHover { get; set; } = true;

    /// <summary>Render clickable indicator dots (one per slide) below the deck.</summary>
    [Parameter] public bool ShowIndicators { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private int _currentIndex;
    private System.Timers.Timer? _autoplayTimer;
    private bool _hovered;
    private bool _focused;
    private bool _canScrollPrev;
    private bool _canScrollNext = true;
    private bool _isDisposed;
    private readonly string _rootId = LumeoIds.New("carousel-root");
    private readonly string _contentId = LumeoIds.New("carousel");
    // A consumer-supplied `id` in AdditionalAttributes overrides the generated
    // one in the DOM, so JS registrations must target the rendered id (Codex P2).
    private string EffectiveRootId => LumeoIds.Effective(AdditionalAttributes, _rootId);
    private string? _registeredNavId;
    private Lumeo.Orientation? _registeredNavOrientation;
    // Item tokens registered by child CarouselItems so the live-region can
    // emit "Slide N of M". The count is the only thing we read from this
    // list — the token objects exist purely so Register/Unregister can be
    // idempotent across re-renders without using indices.
    private readonly List<object> _items = new();

    private string CssClass => Cx.Merge("relative", Class);

    // Indicator dots sit centered on the cross-axis edge: bottom for a
    // horizontal deck, right for a vertical one.
    private string IndicatorWrapClass => Orientation == Lumeo.Orientation.Horizontal
        ? "absolute inset-x-0 bottom-2 z-10 flex items-center justify-center gap-2"
        : "absolute inset-y-0 end-2 z-10 flex flex-col items-center justify-center gap-2";

    private static string IndicatorDotClass(bool active) => Cx.Merge(
        "h-2 w-2 rounded-[calc(var(--radius)*2)] transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2",
        active ? "bg-primary" : "bg-primary/30 hover:bg-primary/50");

    private string SlideAnnouncement => _items.Count > 0
        ? L["Carousel.SlideXofY", _currentIndex + 1, _items.Count]
        : string.Empty;

    private void RegisterItem(object token)
    {
        if (!_items.Contains(token)) _items.Add(token);
        OnItemsChanged();
    }

    private void UnregisterItem(object token)
    {
        if (_items.Remove(token)) OnItemsChanged();
    }

    // CarouselItems register during their OnInitialized as the deck renders its
    // ChildContent — AFTER this component's own render. The indicator dots are
    // driven off _items.Count, so re-render once membership settles to paint
    // them (and keep the count accurate). Guarded on the count to avoid a loop.
    private int _lastRenderedItemCount = -1;
    private void OnItemsChanged()
    {
        // Membership changed (deck grew/shrank, or refilled from empty). The
        // scroll affordances are otherwise only learned from the JS
        // OnScrollPosition callback, so without recomputing here, a Next that
        // went disabled at the old end stays wrongly disabled after more slides
        // are added (and vice-versa). Derive conservatively from the known item
        // range against the current index; a subsequent OnScrollPosition refines
        // them with real pixel measurements.
        _canScrollNext = _items.Count > _currentIndex + 1;
        _canScrollPrev = _currentIndex > 0;
        if (_items.Count != _lastRenderedItemCount)
            InvokeAsync(StateHasChanged);
    }

    protected override void OnParametersSet()
    {
        // Honor Autoplay / AutoplayInterval / Disabled / PauseOnHover changes
        // pushed by the parent at any time.
        SyncAutoplay();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Snapshot the settled item count so OnItemsChanged only re-renders when
        // it actually changes (avoids a render loop from registration).
        _lastRenderedItemCount = _items.Count;

        // Items register during the first child render; start autoplay only
        // once we actually have slides to advance through.
        if (firstRender && Autoplay)
            SyncAutoplay();

        try
        {
            if (firstRender)
            {
                var orientationStr = Orientation == Lumeo.Orientation.Horizontal ? "horizontal" : "vertical";
                await Interop.RegisterCarouselSwipe(
                    _contentId,
                    orientationStr,
                    OnSwipe,
                    OnScrollPosition,
                    GestureOpts.Value.SwipeThresholdPx,
                    GestureOpts.Value.VerticalDeadZonePx
                );
            }

            // Suppress page scroll only for the CURRENT orientation's nav keys,
            // and never when the target is editable slide content. Re-registered
            // whenever the effective id or the Orientation parameter changes —
            // a one-shot firstRender registration kept suppressing the original
            // axis after an orientation switch (Codex P2).
            var navId = EffectiveRootId;
            if (_registeredNavId != navId || _registeredNavOrientation != Orientation)
            {
                if (_registeredNavId is not null)
                    await Interop.UnregisterPreventDefaultKeys(_registeredNavId);
                var navKeys = Orientation == Lumeo.Orientation.Horizontal
                    ? new[] { "ArrowLeft", "ArrowRight" }
                    : new[] { "ArrowUp", "ArrowDown" };
                await Interop.RegisterPreventDefaultKeys(
                    navId,
                    navKeys.Select(k => new PreventDefaultKeyRule(k, SkipEditable: true)).ToArray());
                _registeredNavId = navId;
                _registeredNavOrientation = Orientation;
            }
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private async Task OnSwipe(string direction)
    {
        if (direction == "prev")
            await ScrollPrev();
        else if (direction == "next")
            await ScrollNext();
    }

    private Task OnScrollPosition(double scrollPos, double maxScroll, int nearestIndex)
    {
        var prevP = _canScrollPrev;
        var prevN = _canScrollNext;
        var prevIndex = _currentIndex;
        _canScrollPrev = scrollPos > 0;
        _canScrollNext = scrollPos < maxScroll - 1;
        // Sync _currentIndex from the scroll position so button navigation
        // (ScrollNext/ScrollPrev) stays accurate after touch-swipe.
        if (nearestIndex >= 0)
            _currentIndex = nearestIndex;
        // Also re-render when the index changes for a middle-to-middle swipe
        // — without this the SlideAnnouncement live region stays stale and
        // screen readers don't hear the slide change because prev/next
        // flags remained true on both sides.
        if (prevP != _canScrollPrev || prevN != _canScrollNext || prevIndex != _currentIndex)
            StateHasChanged();
        return Task.CompletedTask;
    }

    private async Task ScrollPrev()
    {
        if (Disabled) return;
        if (!_canScrollPrev && !Loop) return;

        if (_canScrollPrev)
        {
            _currentIndex--;
        }
        else if (Loop)
        {
            _currentIndex = -1;
        }

        await Interop.CarouselScrollTo(_contentId, _currentIndex < 0 ? int.MaxValue : _currentIndex);
        StateHasChanged();
    }

    private async Task ScrollNext()
    {
        if (Disabled) return;
        if (!_canScrollNext && !Loop) return;

        if (_canScrollNext)
        {
            _currentIndex++;
        }
        else if (Loop)
        {
            _currentIndex = 0;
        }

        await Interop.CarouselScrollTo(_contentId, _currentIndex);
        StateHasChanged();
    }

    // Jump straight to a slide (used by the indicator dots). Clamped to the
    // known item range so a stale index can't scroll past the ends.
    private async Task ScrollTo(int index)
    {
        if (Disabled) return;
        if (_items.Count == 0) return;
        index = Math.Clamp(index, 0, _items.Count - 1);
        _currentIndex = index;
        await Interop.CarouselScrollTo(_contentId, index);
        StateHasChanged();
    }

    // --- Autoplay ---

    private bool AutoplayActive => Autoplay && !Disabled && !(PauseOnHover && (_hovered || _focused));

    private void SyncAutoplay()
    {
        if (AutoplayActive)
        {
            if (_autoplayTimer is null)
            {
                _autoplayTimer = new System.Timers.Timer { AutoReset = true };
                _autoplayTimer.Elapsed += OnAutoplayTick;
            }
            // Guard the interval — a 0/negative would throw on Timers.Timer.
            _autoplayTimer.Interval = Math.Max(250, AutoplayInterval);
            _autoplayTimer.Enabled = true;
        }
        else if (_autoplayTimer is not null)
        {
            _autoplayTimer.Enabled = false;
        }
    }

    private void OnAutoplayTick(object? sender, System.Timers.ElapsedEventArgs e)
    {
        // Marshal back onto the renderer's sync context. Advance, wrapping to
        // the first slide at the end (autoplay implies continuous motion even
        // without Loop set, otherwise it would stall on the last slide).
        _ = InvokeAsync(async () =>
        {
            // Guard the dispose race: the timer can fire and queue this callback
            // just as DisposeAsync runs, so bail if we've been torn down.
            if (!AutoplayActive || _isDisposed) return;
            // Best-effort autoplay: a circuit drop / disposal mid-scroll must not
            // surface as an unobserved task exception.
            try
            {
                if (_canScrollNext)
                    await ScrollNext();
                else
                    await ScrollTo(0);
            }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
        });
    }

    private void OnPointerEnter() { _hovered = true; SyncAutoplay(); }
    private void OnPointerLeave() { _hovered = false; SyncAutoplay(); }
    private void OnFocusIn() { _focused = true; SyncAutoplay(); }
    private void OnFocusOut() { _focused = false; SyncAutoplay(); }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (Disabled) return;
        if (Orientation == Lumeo.Orientation.Horizontal)
        {
            var isRtl = EffectiveDirection == LayoutDirection.Rtl;
            var (back, forward) = isRtl ? ("ArrowRight", "ArrowLeft") : ("ArrowLeft", "ArrowRight");
            if (e.Key == back) await ScrollPrev();
            else if (e.Key == forward) await ScrollNext();
        }
        else
        {
            if (e.Key == "ArrowUp") await ScrollPrev();
            else if (e.Key == "ArrowDown") await ScrollNext();
        }
    }

    public async ValueTask DisposeAsync()
    {
        _isDisposed = true;
        if (_autoplayTimer is not null)
        {
            _autoplayTimer.Elapsed -= OnAutoplayTick;
            _autoplayTimer.Dispose();
            _autoplayTimer = null;
        }
        try
        {
            await Interop.UnregisterCarouselSwipe(_contentId);
            // Only unregister what was actually registered — during prerender
            // OnAfterRenderAsync never ran and a JS call here would import the
            // module just to throw (Codex P2 on the PromptInput sibling).
            if (_registeredNavId is not null)
                await Interop.UnregisterPreventDefaultKeys(_registeredNavId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    public record CarouselContext(
        string ContentId,
        Lumeo.Orientation Orientation,
        bool CanScrollPrev,
        bool CanScrollNext,
        EventCallback ScrollPrev,
        EventCallback ScrollNext,
        Action<object> RegisterItem,
        Action<object> UnregisterItem
    );
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (Context.Orientation == Lumeo.Orientation.Horizontal)
    {
        <div id="@Context.ContentId"
             class="flex -ms-4"
             style="overflow-x: auto; scroll-snap-type: x mandatory; scroll-behavior: smooth; -webkit-overflow-scrolling: touch; scrollbar-width: none;">
            @ChildContent
        </div>
    }
    else
    {
        <div id="@Context.ContentId"
             class="flex flex-col -mt-4"
             style="overflow-y: auto; scroll-snap-type: y mandatory; scroll-behavior: smooth; -webkit-overflow-scrolling: touch; scrollbar-width: none;">
            @ChildContent
        </div>
    }
</div>

@code {
    [CascadingParameter] public Carousel.CarouselContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("overflow-hidden", Class);
}

@namespace Lumeo
@implements IDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@{
    var isHorizontal = Context.Orientation == Lumeo.Orientation.Horizontal;
    var cssClass = isHorizontal
        ? Cx.Merge("min-w-0 shrink-0 grow-0 basis-full ps-4", Class)
        : Cx.Merge("min-w-0 shrink-0 grow-0 basis-full pt-4", Class);
}

<div role="group" aria-roledescription="slide" aria-label="@SlideLabel" class="@cssClass" style="scroll-snap-align: start;" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Carousel.CarouselContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int? Index { get; set; }
    [Parameter] public int? Total { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly object _token = new();

    protected override void OnInitialized() => Context?.RegisterItem(_token);
    public void Dispose() => Context?.UnregisterItem(_token);

    private string? SlideLabel => Index.HasValue && Total.HasValue
        ? L["Carousel.SlideXofY", Index.Value, Total.Value]
        : null;
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@{
    var isHorizontal = Context.Orientation == Lumeo.Orientation.Horizontal;
    var positionClass = isHorizontal
        ? "-end-12 top-1/2 -translate-y-1/2"
        : "left-1/2 -translate-x-1/2 -bottom-12";
}

<button class="@(Cx.Merge("absolute h-8 w-8 rounded-[calc(var(--radius)*2)] border bg-background shadow-sm inline-flex items-center justify-center hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50", positionClass, Class))"
        disabled="@(!Context.CanScrollNext)"
        aria-label="@L["Carousel.NextSlide"]"
        @onclick="() => Context.ScrollNext.InvokeAsync()"
        @attributes="AdditionalAttributes">
    @if (isHorizontal)
    {
        <SvgGlyph Svg="@(LumeoIcons.ChevronRight)" class="h-4 w-4 [dir=rtl]:rotate-180" />
    }
    else
    {
        <SvgGlyph Svg="@(LumeoIcons.ChevronDown)" class="h-4 w-4" />
    }
    <span class="sr-only">@L["Carousel.NextSlide"]</span>
</button>

@code {
    [CascadingParameter] public Carousel.CarouselContext Context { get; set; } = default!;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@{
    var isHorizontal = Context.Orientation == Lumeo.Orientation.Horizontal;
    var positionClass = isHorizontal
        ? "-start-12 top-1/2 -translate-y-1/2"
        : "left-1/2 -translate-x-1/2 -top-12";
}

<button class="@(Cx.Merge("absolute h-8 w-8 rounded-[calc(var(--radius)*2)] border bg-background shadow-sm inline-flex items-center justify-center hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50", positionClass, Class))"
        disabled="@(!Context.CanScrollPrev)"
        aria-label="@L["Carousel.PreviousSlide"]"
        @onclick="() => Context.ScrollPrev.InvokeAsync()"
        @attributes="AdditionalAttributes">
    @if (isHorizontal)
    {
        <SvgGlyph Svg="@(LumeoIcons.ChevronLeft)" class="h-4 w-4 [dir=rtl]:rotate-180" />
    }
    else
    {
        <SvgGlyph Svg="@(LumeoIcons.ChevronUp)" class="h-4 w-4" />
    }
    <span class="sr-only">@L["Carousel.PreviousSlide"]</span>
</button>

